import{_ as a,o,c as l,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"38B. Personal Leave Pool","description":"","frontmatter":{"title":"38B. Personal Leave Pool","eba":"Mental Health Services 2024-2028","topics":["leave","personal-leave"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/38B-personal-leave-pool.md","filePath":"ebas/mental-health/common-terms/leave/38B-personal-leave-pool.md"}'),s={name:"ebas/mental-health/common-terms/leave/38B-personal-leave-pool.md"};function n(r,e,p,i,c,h){return o(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="_38b-personal-leave-pool" tabindex="-1">38B. Personal Leave Pool <a class="header-anchor" href="#_38b-personal-leave-pool" aria-label="Permalink to &quot;38B. Personal Leave Pool&quot;">​</a></h1><p><strong>38B.1</strong> The Employer may establish a personal leave pool whereby eligible Employees have access, in defined situations, to additional paid personal leave hours that has been voluntarily donated to the pool by other Employees.</p><p><strong>38B.2</strong> Where this occurs, the Employer will publish criteria that defines the circumstances under which an Employee can (subject to the NES):</p><p><strong>(a)</strong> Donate accrued personal leave,</p><p><strong>(b)</strong> Access personal leave from the personal leave pool.</p><p><strong>38B.3</strong> A donation to a personal leave pool is irrevocable and the personal leave balance of the donating Employee under <a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a> will be adjusted.</p><p>Plain language terms: sick leave pool, extra sick days, pooled personal leave.</p>',7)])])}const v=a(s,[["render",n]]);export{d as __pageData,v as default};
